#include<cstdio>
#include<iostream>
#include<algorithm>
using namespace std;

struct Cow
{
	int w, s;
}a[50005];

bool cmp(Cow x, Cow y)
{
	return x.w + x.s < y.w + y.s;
}

int main(){
	int n, maxn = -2e9;
	cin >> n;
	for(int i = 1; i <= n; i++)
		cin >> a[i].w >> a[i].s;
	sort(a + 1, a + n + 1, cmp);
	int w = 0;
	for(int i = 1; i <= n; i++)
	{
		maxn = max(maxn, w - a[i].s);
		w += a[i].w;
	}
	cout << maxn;
	return 0;
}
